import{_ as s,C as i,o as r,c as d,a5 as l,b as o,w as a,a as E,E as B,a4 as A,j as e}from"./chunks/framework.sOZL8giL.js";const C=JSON.parse('{"title":"上下文的诅咒","description":"","frontmatter":{},"headers":[],"relativePath":"02-上下文工程/01-上下文的诅咒.md","filePath":"02-上下文工程/01-上下文的诅咒.md","lastUpdated":null}'),p={name:"02-上下文工程/01-上下文的诅咒.md"};function g(h,t,f,u,x,m){const n=i("Mermaid");return r(),d("div",null,[t[2]||(t[2]=l('<h1 id="上下文的诅咒" tabindex="-1">上下文的诅咒 <a class="header-anchor" href="#上下文的诅咒" aria-label="Permalink to &quot;上下文的诅咒&quot;">​</a></h1><blockquote><p>本章是 <strong>Hermes Engineering 系列</strong>第 2 模块的第 1 章。</p></blockquote><p>AI 的任务从单次问答进化成持续项目，但上下文越多，模型越容易失焦。这就是上下文的诅咒——它不会报错，只会慢慢变糊。</p><hr><h2 id="从提示工程到上下文工程" tabindex="-1">从提示工程到上下文工程 <a class="header-anchor" href="#从提示工程到上下文工程" aria-label="Permalink to &quot;从提示工程到上下文工程&quot;">​</a></h2><p>我们正在经历一次重要的范式转移：从提示工程（Prompt Engineering）到上下文工程（Context Engineering）。</p><p>提示工程是早期阶段——写好一条完美的提示，核心目标是在一次调用中尽量得到理想的结果。它是战术层面的优化，关注的是那一瞬间的语言表达。但它的局限在于作用范围是点状的，只能让模型聪明一瞬，无法让模型持续聪明。</p><p>随着 Agent 的出现，AI 能够自主规划、调用工具、执行多轮交互任务。性质从一次性问答变成了持续性项目。AI 需要的不再只是一条提示，而是它的完整信息视野——系统指令、可用工具、历史对话记录、从外部数据库检索到的知识。</p><p>上下文工程不再只是写提示，而是一门架构学科。核心任务是动态、持续地为 Agent 策划并管理它完整的上下文状态。我们正在从语言大师变成系统架构师。</p><hr><h2 id="context-rot-上下文腐烂" tabindex="-1">Context Rot：上下文腐烂 <a class="header-anchor" href="#context-rot-上下文腐烂" aria-label="Permalink to &quot;Context Rot：上下文腐烂&quot;">​</a></h2><p>既然模型越来越强，上下文窗口越来越大，为什么不能直接把所有信息都塞进去？</p><p>答案在于所有大模型都无法回避的根本性约束：<strong>上下文腐烂（Context Rot）</strong>——随着上下文中信息量的增加，模型精确回忆以及进行长距离推理的能力会呈现出平滑下降。</p><p>简单说：上下文越长、越嘈杂，模型越容易失焦。</p><h3 id="两个底层原因" tabindex="-1">两个底层原因 <a class="header-anchor" href="#两个底层原因" aria-label="Permalink to &quot;两个底层原因&quot;">​</a></h3><p><strong>架构的内在限制</strong>：所有主流大模型都基于 Transformer 架构，每个 Token 都能关注到上下文中的所有其他 Token，产生 N² 的成对关系。上下文长度每增加一倍，模型需要处理的关系数就几乎增加四倍。就像一个人注意力有限——信息越多，分配到每个细节的注意力就越分散。</p><p><strong>训练数据的分布偏差</strong>：模型在预训练阶段读过无数文本，但大多数是中短序列。它非常擅长处理短序列文本，但对长文本的经验极度有限。</p><p>上下文腐烂的危险特征在于它是结构性的——不是立刻崩溃，而是性能渐进退化。模型不会告诉你&quot;我不行了&quot;，但会开始答非所问、遗漏重点、逻辑漂移。这是最危险的地方——因为它不会报错，只会慢慢变糊。</p><hr><h2 id="四种失效模式" tabindex="-1">四种失效模式 <a class="header-anchor" href="#四种失效模式" aria-label="Permalink to &quot;四种失效模式&quot;">​</a></h2><p>上下文腐烂是底层状态，在具体任务中它会表现为四种可被诊断的失败模式：</p><p><strong>上下文污染（Contamination）</strong>：一次幻觉或错误信息渗入上下文中，还被后续推理当做事实依据。一旦有毒数据进入 Agent 的认知循环，后续基于此的所有决策链条都可能被污染。</p><p><strong>上下文干扰（Interference）</strong>：上下文信息过多，压倒了模型的预训练知识。大量低价值即时信息淹没模型固有的知识信号，让它在噪声中迷失做出违背常识的判断。</p><p><strong>上下文混淆（Confusion）</strong>：多余不相关的语境信息影响了最终回应。模型注意力被稀释，无法清晰追踪核心逻辑，把两个不相关概念错误关联。</p><p><strong>上下文冲突（Conflict）</strong>：上下文中不同部分包含相互矛盾的信息。系统提示要求&quot;保持简洁&quot;，但历史对话中却有很多冗长例子——模型陷入决策困境，行为混乱或犹豫不决。</p><h3 id="因果关系" tabindex="-1">因果关系 <a class="header-anchor" href="#因果关系" aria-label="Permalink to &quot;因果关系&quot;">​</a></h3><p>上下文腐烂是根本病因，四种失效模式是具体并发症。一个精神饱满的司机，就算遇到烂路也能成功应对；但一个疲劳的司机，处理烂路的能力大大下降，出车祸概率大大增加。</p><p>上下文腐烂导致的注意力稀释和信噪比降低，会直接引发干扰和混淆。在腐烂状态下模型推理能力下降，更容易产生幻觉从而主动制造污染源头。腐烂状态还屏蔽问题发现——模型可能发现不了上下文中早已存在的语境冲突，因为相隔较远的两条矛盾信息已经超出了有效的注意力范围。</p>',28)),(r(),o(A,null,{default:a(()=>[B(n,{id:"mermaid-80",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5BContext%20Rot%3Cbr%2F%3E%E4%B8%8A%E4%B8%8B%E6%96%87%E8%85%90%E7%83%82%5D%20--%3E%20B%5B%E4%B8%8A%E4%B8%8B%E6%96%87%E6%B1%A1%E6%9F%93%3Cbr%2F%3E%E5%B9%BB%E8%A7%89%E6%B8%97%E5%85%A5%E8%A2%AB%E5%BD%93%E4%BA%8B%E5%AE%9E%5D%0A%20%20%20%20A%20--%3E%20C%5B%E4%B8%8A%E4%B8%8B%E6%96%87%E5%B9%B2%E6%89%B0%3Cbr%2F%3E%E4%BD%8E%E4%BB%B7%E5%80%BC%E4%BF%A1%E6%81%AF%E6%B7%B9%E6%B2%A1%E5%B8%B8%E8%AF%86%5D%0A%20%20%20%20A%20--%3E%20D%5B%E4%B8%8A%E4%B8%8B%E6%96%87%E6%B7%B7%E6%B7%86%3Cbr%2F%3E%E6%B3%A8%E6%84%8F%E5%8A%9B%E7%A8%80%E9%87%8A%E9%94%99%E8%AF%AF%E5%85%B3%E8%81%94%5D%0A%20%20%20%20A%20--%3E%20E%5B%E4%B8%8A%E4%B8%8B%E6%96%87%E5%86%B2%E7%AA%81%3Cbr%2F%3E%E7%9F%9B%E7%9B%BE%E4%BF%A1%E6%81%AF%E5%AF%BC%E8%87%B4%E8%A1%8C%E4%B8%BA%E6%B7%B7%E4%B9%B1%5D%0A%20%20%20%20B%20--%3E%20F%5B%E5%86%B3%E7%AD%96%E9%93%BE%E6%9D%A1%E8%A2%AB%E6%B1%A1%E6%9F%93%5D%0A%20%20%20%20C%20--%3E%20G%5B%E8%BF%9D%E8%83%8C%E5%B8%B8%E8%AF%86%E7%9A%84%E5%88%A4%E6%96%AD%5D%0A%20%20%20%20D%20--%3E%20H%5B%E6%A0%B8%E5%BF%83%E9%80%BB%E8%BE%91%E4%B8%A2%E5%A4%B1%5D%0A%20%20%20%20E%20--%3E%20I%5B%E6%A8%A1%E5%9E%8B%E7%8A%B9%E8%B1%AB%E6%B7%B7%E4%B9%B1%5D%0A%20%20%20%20F%20--%3E%20J%5B%E7%B3%BB%E7%BB%9F%E8%BE%93%E5%87%BA%E8%B4%A8%E9%87%8F%E4%B8%8B%E9%99%8D%5D%0A%20%20%20%20G%20--%3E%20J%0A%20%20%20%20H%20--%3E%20J%0A%20%20%20%20I%20--%3E%20J%0A"})]),fallback:a(()=>[...t[0]||(t[0]=[E(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=e("blockquote",null,[e("p",null,[E("💡 "),e("strong",null,"图解："),E(" Context Rot 是病因，四种失效模式是并发症——模型不会报错，只会慢慢变糊。")])],-1)),t[4]||(t[4]=e("hr",null,null,-1)),t[5]||(t[5]=e("h2",{id:"逻辑链",tabindex:"-1"},[E("逻辑链 "),e("a",{class:"header-anchor",href:"#逻辑链","aria-label":'Permalink to "逻辑链"'},"​")],-1)),(r(),o(A,null,{default:a(()=>[B(n,{id:"mermaid-90",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%E4%BB%BB%E5%8A%A1%E8%BF%9B%E5%8C%96%3Cbr%2F%3E%E5%8D%95%E6%AC%A1%E9%97%AE%E7%AD%94%E2%86%92%E6%8C%81%E7%BB%AD%E9%A1%B9%E7%9B%AE%5D%20--%3E%20B%5BAgent%20%E4%BE%9D%E8%B5%96%E5%8A%A8%E6%80%81%E4%B8%8A%E4%B8%8B%E6%96%87%5D%0A%20%20%20%20B%20--%3E%20C%5BTransformer%20N%C2%B2%E7%BA%A6%E6%9D%9F%3Cbr%2F%3E%2B%E8%AE%AD%E7%BB%83%E6%95%B0%E6%8D%AE%E5%81%8F%E5%B7%AE%5D%0A%20%20%20%20C%20--%3E%20D%5BContext%20Rot%5D%0A%20%20%20%20D%20--%3E%20E%5B%E4%B8%8A%E4%B8%8B%E6%96%87%E5%B7%A5%E7%A8%8B%E6%88%90%E4%B8%BA%3Cbr%2F%3E%E5%BF%85%E4%BF%AE%E8%AF%BE%5D%0A"})]),fallback:a(()=>[...t[1]||(t[1]=[E(" Loading... ",-1)])]),_:1})),t[6]||(t[6]=l('<blockquote><p>💡 <strong>图解：</strong> 任务复杂度的进化撞上了 Transformer 的物理墙——不主动设计上下文，腐烂就会吞噬 Agent 的判断力。</p></blockquote><p>任务进化（从单次问答到持续项目）→ Agent 运行依赖动态上下文环境 → Transformer 结构决定了上下文越多性能越可能腐烂 → <strong>上下文工程成为构建高可靠 Agent 的必修课</strong>。</p><p>真正的解决方案不是被动等待一个无限大的内存，而是成为一名主动的上下文架构师——用工程方法来主动设计上下文，让模型始终保持清晰与聚焦。</p><hr><h2 id="⚠️-常见错误" tabindex="-1">⚠️ 常见错误 <a class="header-anchor" href="#⚠️-常见错误" aria-label="Permalink to &quot;⚠️ 常见错误&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">❌ 错误做法</th><th style="text-align:left;">✅ 正确做法</th><th style="text-align:left;">为什么</th></tr></thead><tbody><tr><td style="text-align:left;">把所有信息都塞进上下文，&quot;窗口够大就行&quot;</td><td style="text-align:left;">主动设计上下文——只注入下一步决策需要的信息</td><td style="text-align:left;">Context Rot 是结构性的：Transformer N² 约束 + 训练数据偏差，上下文越长性能越差，不会报错只会慢慢变糊</td></tr><tr><td style="text-align:left;">一次幻觉渗入上下文后继续当事实使用</td><td style="text-align:left;">保留错误信息但标记隔离，让 Agent 从失败中学习</td><td style="text-align:left;">上下文污染一旦进入认知循环，后续所有决策链条都可能被污染——有毒数据会产生连锁反应</td></tr><tr><td style="text-align:left;">上下文中塞满工具返回的原始日志</td><td style="text-align:left;">子 Agent 过滤噪声，只返回 50-200 Token 关键信息</td><td style="text-align:left;">上下文干扰：大量低价值信息淹没模型预训练知识，让 Agent 在噪声中做出违背常识的判断</td></tr><tr><td style="text-align:left;">系统提示要求简洁，但历史对话中大量冗长例子</td><td style="text-align:left;">保持指令风格一致，矛盾信息必须消除</td><td style="text-align:left;">上下文冲突让模型陷入决策困境——不同部分的矛盾指令导致行为混乱或犹豫不决</td></tr><tr><td style="text-align:left;">把无关的上下文也保留&quot;以防万一&quot;</td><td style="text-align:left;">只保留与当前任务相关的语境信息</td><td style="text-align:left;">上下文混淆：注意力被稀释，模型把两个不相关概念错误关联，核心逻辑丢失</td></tr></tbody></table><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>范式转移：从提示工程到上下文工程，从语言大师到系统架构师</li><li>Context Rot：Transformer 架构限制 + 训练数据偏差，上下文越长性能越差</li><li>四种失效模式：污染、干扰、混淆、冲突，上下文腐烂是病因它们是并发症</li><li>解决之道不是等更大的窗口，而是主动设计上下文</li></ul><hr><p><strong>下一章</strong>: <a href="./02-三大支柱.html">三大支柱</a></p><hr><p><a href="/">← 返回首页</a> | <a href="/01-Harness工程核心原则/">← 上一模块: Harness工程核心原则</a> | <a href="/03-Agent基础/">下一模块: Agent基础 →</a></p>',13))])}const D=s(p,[["render",g]]);export{C as __pageData,D as default};
